package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    public void testIsEscapeCharacterSet_whenEscapeCharacterIsNull() throws Exception {
        CSVFormat format = CSVFormat.newFormat(',');
        // Using reflection to set escapeCharacter to null explicitly (should be null by default)
        setEscapeCharacter(format, null);
        assertFalse(format.isEscapeCharacterSet());
    }

    @Test
    public void testIsEscapeCharacterSet_whenEscapeCharacterIsSet() throws Exception {
        CSVFormat format = CSVFormat.newFormat(',');
        // Using reflection to set escapeCharacter to some character
        setEscapeCharacter(format, '\\');
        assertTrue(format.isEscapeCharacterSet());
    }

    private void setEscapeCharacter(CSVFormat format, Character escapeChar) throws Exception {
        Field escapeCharacterField = CSVFormat.class.getDeclaredField("escapeCharacter");
        escapeCharacterField.setAccessible(true);
        escapeCharacterField.set(format, escapeChar);
    }
}
